/*:
 * @target MZ
 * @plugindesc v1.1.3 Build Parallax maps in realtime using a visual editor
 * @author Sang Hendrix
 * @url https://sanghendrix.itch.io
 * 
 * @help
 * Version 1.1.3
 * For support or bug report, please contact via Discord
 * Discord: https://discord.gg/YKPscqHV8b
 * ----------------------------------------------------------------------------
 * This RPG Maker MZ plugin allows you to create parallax maps in real time
 * using a visual editor (WYSIWYG). Easily manage your layers and settings,
 * and see changes reflected in-game instantly.
 * ----------------------------------------------------------------------------
 * HOW TO USE
 * ----------------------------------------------------------------------------
 * 1. Assign the button you want to press to call the Visual Editor, by default,
 * it's 'pagedown', which is 'W' in RPG Maker MZ
 * 2. Open Visual Editor and click on + button to create a new layer
 * 3. You know the rest, it's that easy
 * 
 * - All settings are saved to ParallaxSettings.json in the js folder
 * - Changes are saved immediately
 * ----------------------------------------------------------------------------
 * TUTORIALS AND STUFF
 * ----------------------------------------------------------------------------
 * Youtube: https://www.youtube.com/SangHendrix
 * Plugin page: https://sanghendrix.itch.io/realtime-parallax-map-builder-rpg-maker-mz-plugin
 * ----------------------------------------------------------------------------
 *
 * @param visualEditorButton
 * @text Visual Editor Button
 * @desc Button to open the visual editor
 * @type select
 * @option Shift
 * @value shift
 * @option Control
 * @value control
 * @option Tab
 * @value tab
 * @option Page Up
 * @value pageup
 * @option Page Down
 * @value pagedown
 * @option Menu/X
 * @value menu
 * @default pagedown
 * 
 * @param alwaysRunGame
 * @text Always Run Game
 * @desc Keep game running even when window loses focus (recommended TRUE for visual editor)
 * @type boolean
 * @default true
 * 
 * @command controlMapLayer
 * @text Control Map Layer
 * @desc Hide, show, or delete a parallax layer by name
 * 
 * @arg layerName
 * @text Layer Name
 * @desc Name of the layer to control
 * @type string
 * @default
 * 
 * @arg action
 * @text Action
 * @desc Action to do
 * @type select
 * @option Hide
 * @value hide
 * @option Show
 * @value show
 * @option Delete
 * @value delete
 * @default hide
 * 
 * @arg permanent
 * @text Permanent
 * @desc If true, save to JSON. If false, temporary change (resets on map reload)
 * @type boolean
 * @default true
 */

var Imported = Imported || {};
Imported.Hendrix_Realtime_Parallax_Map_Builder = true;

